#!/usr/bin/env node
/**
 * Bundle the IBM VGA 8x16 font as a base64 data URL.
 *
 * This script:
 * 1. Reads the TTF font file
 * 2. Base64 encodes it
 * 3. Outputs a TypeScript file with IBM_VGA_FONT_DATA_URL export
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const FONT_FILE = join(__dirname, '..', '..', '..', 'lua-learning-website', 'public', 'fonts', 'WebPlus_IBM_VGA_8x16.woff');
const OUTPUT_DIR = join(__dirname, '..', 'src');
const OUTPUT_TS = join(OUTPUT_DIR, 'ibm-vga-font-inline.generated.ts');

function bundleFont() {
  console.log('Bundling IBM VGA font for inline exports...');

  if (!existsSync(FONT_FILE)) {
    throw new Error(`Font file not found at ${FONT_FILE}`);
  }

  const fontData = readFileSync(FONT_FILE);
  console.log(`  Read font: ${fontData.length} bytes`);

  const base64 = fontData.toString('base64');
  const dataUrl = `data:font/woff;base64,${base64}`;
  console.log(`  Data URL: ${dataUrl.length} chars`);

  const tsContent = `/**
 * Auto-generated IBM VGA 8x16 font as data URL.
 * DO NOT EDIT THIS FILE DIRECTLY.
 *
 * Run "npm run build:font" to regenerate this file.
 */
export const IBM_VGA_FONT_DATA_URL = '${dataUrl}'
`;

  if (!existsSync(OUTPUT_DIR)) {
    mkdirSync(OUTPUT_DIR, { recursive: true });
  }

  writeFileSync(OUTPUT_TS, tsContent);
  console.log(`Generated: ibm-vga-font-inline.generated.ts (${fontData.length} bytes font)`);
}

bundleFont();
